export const handle = async (request, response) => {
    const { scheduleBody } = request.inputs;
    const schedule = JSON.parse(scheduleBody);
    const events = schedule.events || [];

    const dayNamesEn = ["Monday", "Tuesday", "Wednesday", "Thursday",
                        "Friday", "Saturday", "Sunday"];
    const dayNamesEs = ["lunes", "martes", "miércoles", "jueves",
                        "viernes", "sábado", "domingo"];
    const dayKeys   = ["monday", "tuesday", "wednesday", "thursday",
                       "friday", "saturday", "sunday"];

    function formatTime(t) {
        const h = parseInt(t.split(":")[0], 10);
        if (h === 0) return "12 AM";
        if (h < 12) return h + " AM";
        if (h === 12) return "12 PM";
        return (h - 12) + " PM";
    }

    function getActiveDays(weekly) {
        return dayKeys
            .map((k, i) => weekly[k] ? i : -1)
            .filter(i => i >= 0);
    }

    function groupRanges(active) {
        const ranges = [];
        let start = active[0], end = active[0];
        for (let i = 1; i < active.length; i++) {
            if (active[i] === end + 1) {
                end = active[i];
            } else {
                ranges.push([start, end]);
                start = active[i];
                end = active[i];
            }
        }
        ranges.push([start, end]);
        return ranges;
    }

    function formatDaysEn(weekly) {
        const active = getActiveDays(weekly);
        if (active.length === 7) return "every day";
        if (active.length === 0) return "";
        const ranges = groupRanges(active);
        return ranges.map(([s, e]) => {
            if (s === e) return dayNamesEn[s];
            if (e - s === 1) return dayNamesEn[s] + " and " + dayNamesEn[e];
            return dayNamesEn[s] + " through " + dayNamesEn[e];
        }).join(", ");
    }

    function formatDaysEs(weekly) {
        const active = getActiveDays(weekly);
        if (active.length === 7) return "todos los días";
        if (active.length === 0) return "";
        const ranges = groupRanges(active);
        return ranges.map(([s, e]) => {
            if (s === e) return dayNamesEs[s];
            if (e - s === 1) return dayNamesEs[s] + " y " + dayNamesEs[e];
            return dayNamesEs[s] + " a " + dayNamesEs[e];
        }).join(", ");
    }

    const sentencesEn = events
        .filter(ev => ev.recurrence && ev.recurrence.recurWeekly)
        .map(ev => {
            const days = formatDaysEn(ev.recurrence.recurWeekly);
            if (!days) return null;
            return days + " " + formatTime(ev.startTime)
                + " to " + formatTime(ev.endTime);
        })
        .filter(Boolean);

    const sentencesEs = events
        .filter(ev => ev.recurrence && ev.recurrence.recurWeekly)
        .map(ev => {
            const days = formatDaysEs(ev.recurrence.recurWeekly);
            if (!days) return null;
            return days + " de " + formatTime(ev.startTime)
                + " a " + formatTime(ev.endTime);
        })
        .filter(Boolean);

    const ttsMessage = sentencesEn.length > 0
        ? "We are open " + sentencesEn.join(", ") + "."
        : "Store hours are not available for this location.";

    const ttsMessageEs = sentencesEs.length > 0
        ? "Estamos abiertos de " + sentencesEs.join(", ") + "."
        : "El horario de la tienda no está disponible para esta ubicación.";

    response.data = { ttsMessage, ttsMessageEs };
    return response;
}
